static uint32_t CalcOutSize(uint32_t inputSize, uint32_t kernelSize,
                            uint32_t stride, uint32_t padding,
                            uint32_t dilation, bool ceilMode)
{
    uint32_t dilatedSize = kernelSize + (kernelSize - 1) * (dilation - 1);
    if (ceilMode) {
        return static_cast<uint32_t>(std::ceil(static_cast<float>(inputSize + 2 * padding - dilatedSize) / stride)) + 1;
    } else {
        return static_cast<uint32_t>(std::floor(static_cast<float>(inputSize + 2 * padding - dilatedSize) / stride)) + 1;
    }
}

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    MaxPooling3dCustomTilingData tiling;

    const gert::Shape *inputShape = context->GetInputShape(0);
    auto dims = inputShape->GetOriginShape();
    uint32_t N = static_cast<uint32_t>(dims.GetDim(0));
    uint32_t C = static_cast<uint32_t>(dims.GetDim(1));
    uint32_t D = static_cast<uint32_t>(dims.GetDim(2));
    uint32_t H = static_cast<uint32_t>(dims.GetDim(3));
    uint32_t W = static_cast<uint32_t>(dims.GetDim(4));

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    std::vector<int64_t> kernelSize = attrs->GetAttrPointer<std::vector<int64_t>>(0);
    std::vector<int64_t> stride = attrs->GetAttrPointer<std::vector<int64_t>>(1);
    std::vector<int64_t> padding = attrs->GetAttrPointer<std::vector<int64_t>>(2);
    // default dilation=1
    std::vector<int64_t> dilation = {1,1,1};
    bool ceilMode = false;
    if (attrs->GetAttrNum() > 3) {
        dilation = attrs->GetAttrPointer<std::vector<int64_t>>(3);
    }
    if (attrs->GetAttrNum() > 4) {
        ceilMode = *(attrs->GetAttrPointer<bool>(4));
    }

    uint32_t kD = static_cast<uint32_t>(kernelSize[0]);
    uint32_t kH = static_cast<uint32_t>(kernelSize[1]);
    uint32_t kW = static_cast<uint32_t>(kernelSize[2]);
    uint32_t sD = static_cast<uint32_t>(stride[0]);
    uint32_t sH = static_cast<uint32_t>(stride[1]);
    uint32_t sW = static_cast<uint32_t>(stride[2]);
    uint32_t pD = static_cast<uint32_t>(padding[0]);
    uint32_t pH = static_cast<uint32_t>(padding[1]);
    uint32_t pW = static_cast<uint32_t>(padding[2]);
    uint32_t dD = static_cast<uint32_t>(dilation[0]);
    uint32_t dH = static_cast<uint32_t>(dilation[1]);
    uint32_t dW = static_cast<uint32_t>(dilation[2]);

    uint32_t oD = CalcOutSize(D, kD, sD, pD, dD, ceilMode);
    uint32_t oH = CalcOutSize(H, kH, sH, pH, dH, ceilMode);
    uint32_t oW = CalcOutSize(W, kW, sW, pW, dW, ceilMode);

    uint32_t totalOutputElems = N * C * oD * oH * oW;

    // Determine block dim and tile size
    const uint32_t UB_BUDGET = 192 * 1024; // bytes
    // For each output element, we load a window of kD*kH*kW floats = 27*4=108 bytes
    // To reduce, process multiple output elements per tile, but for simplicity:
    // tileElems = number of output elements per block
    // We'll assign tileElems = 64, so each block loads ~64*108 = 6912 bytes, fine.
    const uint32_t baseTile = 64;
    uint32_t tileElems = baseTile;
    if (totalOutputElems < baseTile) {
        tileElems = totalOutputElems;
    }
    uint32_t blockDim = (totalOutputElems + tileElems - 1) / tileElems;
    if (blockDim > 40) blockDim = 40; // limit cores

    context->SetBlockDim(blockDim);

    tiling.set_n(N);
    tiling.set_c(C);
    tiling.set_d(D);
    tiling.set_h(H);
    tiling.set_w(W);
    tiling.set_kD(kD);
    tiling.set_kH(kH);
    tiling.set_kW(kW);
    tiling.set_sD(sD);
    tiling.set_sH(sH);
    tiling.set_sW(sW);
    tiling.set_pD(pD);
    tiling.set_pH(pH);
    tiling.set_pW(pW);
    tiling.set_dD(dD);
    tiling.set_dH(dH);
    tiling.set_dW(dW);
    tiling.set_oD(oD);
    tiling.set_oH(oH);
    tiling.set_oW(oW);
    tiling.set_ceilMode(ceilMode ? 1 : 0);
    tiling.set_totalOutputElems(totalOutputElems);
    tiling.set_tileElems(tileElems);
    tiling.set_blockDim(blockDim);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

