static ge::graphStatus InferShape(gert::InferShapeContext *context)
{
    const gert::Shape *inputShape = context->GetInputShape(0);
    auto dims = inputShape->GetOriginShape();
    uint32_t N = static_cast<uint32_t>(dims.GetDim(0));
    uint32_t C = static_cast<uint32_t>(dims.GetDim(1));
    uint32_t D = static_cast<uint32_t>(dims.GetDim(2));
    uint32_t H = static_cast<uint32_t>(dims.GetDim(3));
    uint32_t W = static_cast<uint32_t>(dims.GetDim(4));

    // Need attributes to compute output shape. For simplicity, assume same as host_tiling.
    // Actually we need to repeat calc here. But we can copy from tiling data? Not available.
    // We'll rely on tiling data being available at runtime. For InferShape, we can use default.
    // For correctness, we should parse attrs again. But to keep it short, we'll not implement full computation.
    // The actual shape will be set by the framework from the tiling data? Typically InferShape should compute shape exactly.
    // We'll compute using same logic as TilingFunc.
    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    std::vector<int64_t> kernelSize = attrs->GetAttrPointer<std::vector<int64_t>>(0);
    std::vector<int64_t> stride = attrs->GetAttrPointer<std::vector<int64_t>>(1);
    std::vector<int64_t> padding = attrs->GetAttrPointer<std::vector<int64_t>>(2);
    std::vector<int64_t> dilation = {1,1,1};
    bool ceilMode = false;
    if (attrs->GetAttrNum() > 3) dilation = attrs->GetAttrPointer<std::vector<int64_t>>(3);
    if (attrs->GetAttrNum() > 4) ceilMode = *(attrs->GetAttrPointer<bool>(4));

    auto calc = [](uint32_t in, uint32_t k, uint32_t s, uint32_t p, uint32_t d, bool ceil) -> uint32_t {
        uint32_t dilated = k + (k-1)*(d-1);
        if (ceil) return static_cast<uint32_t>(std::ceil((in + 2*p - dilated)/s) + 1);
        else return static_cast<uint32_t>(std::floor((in + 2*p - dilated)/s) + 1);
    };

    uint32_t oD = calc(D, kernelSize[0], stride[0], padding[0], dilation[0], ceilMode);
    uint32_t oH = calc(H, kernelSize[1], stride[1], padding[1], dilation[1], ceilMode);
    uint32_t oW = calc(W, kernelSize[2], stride[2], padding[2], dilation[2], ceilMode);

    gert::Shape *outShape = context->GetOutputShape(0);
    outShape->SetDimNum(5);
    outShape->SetDim(0, static_cast<int64_t>(N));
    outShape->SetDim(1, static_cast<int64_t>(C));
    outShape->SetDim(2, static_cast<int64_t>(oD));
    outShape->SetDim(3, static_cast<int64_t>(oH));
    outShape->SetDim(4, static_cast<int64_t>(oW));
    return GRAPH_SUCCESS;
}

